private handleConnection(ws: WebSocket): void {
  // Close existing connection if any (graceful replacement)
  if (this.currentConnection) {
    logEvent(null, 'info', 'Replacing existing CDC Worker connection');
    this.currentConnection.close(1000, 'Replaced by new connection');
  }

  this.currentConnection = ws;
  this._cdcConnected = true;
  this.resetIdleTimer();
  this.startPingInterval();

  logEvent(null, 'info', 'CDC Worker connected via WebSocket');

  ws.on('message', (data) => {
    this.resetIdleTimer();
    this.handleMessage(data.toString());
  });

  ws.on('pong', () => {
    this.resetIdleTimer();
  });

  ws.on('close', (code, reason) => {
    logEvent(null, 'info', 'CDC Worker disconnected', { code, reason: reason.toString() });
    this.cleanup();
  });

  ws.on('error', (err) => {
    logEvent(null, 'error', 'CDC WebSocket error', { error: err.message });
    this.cleanup();
  });
}

publicCache = (entityType: ProductEntityType, idParam = 'id'): MiddlewareHandler<Env> =>
  xMiddleware(
    {
      functionName: 'publicCache',
      type: 'x-cache',
      name: 'public',
      description: `LRU cache for public ${entityType} entities`,
    },
    async (ctx, next) => {
      // Extract entity ID from route params
      const entityId = ctx.req.param(idParam);

      if (!entityId) {
        ctx.set('entityCacheHit', false);
        await next();
        return;
      }

      // Check LRU cache
      const cached = publicEntityCache.get(entityType, entityId);

      if (cached) {
        ctx.set('entityCacheHit', true);
        ctx.header('X-Cache', 'HIT');
        return ctx.json(cached);
      }

      // Cache miss - proceed to handler for fetch/enrichment
      ctx.set('entityCacheHit', false);

      await next();

      // After handler: cache the response if data was set
      const entityData = ctx.get('entityCacheData');

      if (entityData) {
        publicEntityCache.set(entityType, entityId, entityData);
        ctx.header('X-Cache', 'MISS');
      }
    },
  )

async function deleteR2Objects(
	c: AppContext,
	bucket_name: string,
	body: DeleteObjectsBody
): Promise<Response> {
	const keys = body;
	if (keys.length === 0) {
		return errorResponse(
			400,
			10001,
			"Request body must be a non-empty array of keys"
		);
	}

	// Try local first
	const r2 = getR2Binding(c.env, bucket_name);
	if (r2) {
		await r2.delete(keys);
		return c.json(wrapResponse(keys.map((key) => ({ key }))));
	}

	const ownerMiniflare = await findR2BucketOwner(c, bucket_name);
	if (ownerMiniflare) {
		const path = `/r2/buckets/${encodeURIComponent(bucket_name)}/objects`;
		const response = await fetchFromPeer(ownerMiniflare, path, {
			method: "DELETE",
			headers: { "Content-Type": "application/json" },
			body: JSON.stringify(keys),
		});
		if (response) return response;
	}

	return errorResponse(
		404,
		R2_ERROR_BUCKET_NOT_FOUND,
		"delete: 'bucket not found'"
	);
}

function ajvValidator<
  T,
  Target extends keyof ValidationTargets,
  E extends Env = Env,
  P extends string = string,
>(
  target: Target,
  schema: JSONSchemaType<T>,
  hook?: Hook<T, E, P>
): MiddlewareHandler<
  E,
  P,
  {
    in: { [K in Target]: T }
    out: { [K in Target]: T }
  }
> {
  const ajv = new Ajv()
  const validate = ajv.compile(schema)
  // @ts-expect-error not typed well
  return validator(target, (data, c) => {
    const valid = validate(data)
    if (valid) {
      if (hook) {
        const hookResult = hook({ success: true, data: data as T }, c)
        if (hookResult) {
          return hookResult
        }
      }
      return data
    }

    const errors = validate.errors || []
    if (hook) {
      const hookResult = hook({ success: false, errors }, c)
      if (hookResult) {
        return hookResult
      }
    }
    return c.json({ success: false, errors }, 400)
  })
}

async function getAuthUser(c: Context): Promise<AuthUser | null> {
  const config = c.get('authConfig')
  const ctxEnv = env(c) as AuthEnv
  setEnvDefaults(ctxEnv, config)
  const authReq = reqWithEnvUrl(c.req.raw, ctxEnv.AUTH_URL)
  const origin = new URL(authReq.url).origin
  const request = new Request(`${origin}${config.basePath}/session`, {
    headers: { cookie: c.req.header('cookie') ?? '' },
  })

  let authUser: AuthUser = {} as AuthUser

  const response = (await Auth(request, {
    ...config,
    callbacks: {
      ...config.callbacks,
      async session(...args) {
        authUser = args[0]
        const session = (await config.callbacks?.session?.(...args)) ?? args[0].session
        const user = args[0].user ?? args[0].token
        return { user, ...session } satisfies Session
      },
    },
  })) as Response

  const session = (await response.json()) as Session | null

  return session?.user ? authUser : null
}

jwtAuthorizer = async (
  c: Context,
  enforcer: Enforcer,
  claimMapping: Record<string, string> = { userID: 'sub' }
): Promise<boolean> => {
  // Note: if use hono/jwt, the payload is stored in c.get('jwtPayload')
  // https://github.com/honojs/hono/blob/8ba02273e829318d7f8797267f52229e531b8bd5/src/middleware/jwt/jwt.ts#L136
  let payload: JWTPayload = c.get('jwtPayload')

  if (!payload) {
    const credentials = c.req.header('Authorization')
    if (!credentials) {
      return false
    }

    const parts = credentials.split(/\s+/)
    if (parts.length !== 2 || parts[0] !== 'Bearer') {
      return false
    }

    const token = parts[1]

    try {
      const decoded = decode(token)
      payload = decoded.payload
    } catch {
      return false
    }
  }

  const args = Object.values(claimMapping).map((key) => payload[key])

  const { path, method } = c.req
  return await enforcer.enforce(...args, path, method)
}

async exchangeRefreshToken(
  client: OAuthClientInformationFull,
  refreshToken: string,
  scopes?: string[],
  resource?: URL
): Promise<OAuthTokens> {
  const params = new URLSearchParams({
    grant_type: 'refresh_token',
    client_id: client.client_id,
    refresh_token: refreshToken,
  })

  if (client.client_secret) {
    params.set('client_secret', client.client_secret)
  }

  if (scopes?.length) {
    params.set('scope', scopes.join(' '))
  }

  if (resource) {
    params.set('resource', resource.href)
  }

  const response = await (this._fetch ?? fetch)(this._endpoints.tokenUrl, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
    },
    body: params.toString(),
  })

  if (!response.ok) {
    throw new ServerError(`Token refresh failed: ${response.status}`)
  }

  const data = await response.json()
  return OAuthTokensSchema.parse(data)
}

private async getTokenFromCode() {
  const response = (await fetch('https://github.com/login/oauth/access_token', {
    method: 'POST',
    body: JSON.stringify({
      client_id: this.client_id,
      client_secret: this.client_secret,
      code: this.code,
    }),
    headers: { Accept: 'application/json', 'Content-Type': 'application/json' },
  }).then((res) => res.json())) as GitHubTokenResponse | GitHubErrorResponse

  if ('error_description' in response) {
    throw new HTTPException(400, { message: response.error_description })
  }

  if ('access_token' in response) {
    this.token = {
      token: response.access_token,
      expires_in: response.expires_in,
    }
    this.granted_scopes = response.scope.split(',')

    if (response.refresh_token && response.refresh_token_expires_in) {
      this.refresh_token = {
        token: response.refresh_token,
        expires_in: response.refresh_token_expires_in,
      }
    }
  }
}

private async getTokenFromCode() {
  const params = toQueryParams({
    grant_type: 'authorization_code',
    code: this.code,
    client_id: this.client_id,
    client_secret: this.client_secret,
    redirect_uri: this.redirect_uri,
  })

  const response = (await fetch(`https://www.linkedin.com/oauth/v2/accessToken?${params}`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
    },
  }).then((res) => res.json())) as LinkedInTokenResponse | LinkedInErrorResponse

  if ('error' in response) {
    throw new HTTPException(400, { message: response.error_description })
  }

  if ('access_token' in response) {
    this.token = {
      token: response.access_token,
      expires_in: response.expires_in,
    }
    this.refresh_token = {
      token: response.refresh_token,
      expires_in: response.refresh_token_expires_in,
    }

    this.granted_scopes = response.scope?.split(',')
  }
}

async getTokenFromCode(): Promise<void> {
  const parsedOptions = toQueryParams({
    client_id: this.client_id,
    client_secret: this.client_secret,
    redirect_uri: this.redirect_uri,
    code: this.code,
    grant_type: 'authorization_code',
  })
  const response = (await fetch(
    `https://login.microsoft.com/${this.tenant_id}/oauth2/v2.0/token`,
    {
      method: 'POST',
      headers: {
        'content-type': 'application/x-www-form-urlencoded',
      },
      body: parsedOptions,
    }
  ).then((res) => res.json())) as MSEntraTokenResponse | MSEntraErrorResponse

  if ('error' in response) {
    throw new HTTPException(400, { message: response.error })
  }

  if ('access_token' in response) {
    this.token = {
      token: response.access_token,
      expires_in: response.expires_in,
      refresh_token: response.refresh_token,
    }

    this.granted_scopes = response.scope.split(' ')
  }
}

createStandardMetrics = ({
  registry,
  prefix = '',
  customOptions,
}: {
  registry: Registry
  prefix?: string
  customOptions?: CustomMetricsOptions
}) => {
  const createdMetrics: Record<string, Metric> = {}

  for (const [metric, options] of Object.entries(standardMetrics)) {
    const opts: MetricOptions = {
      ...options,
      ...customOptions?.[metric as MetricName],
    }

    if (opts.disabled) {
      continue
    }

    const MetricConstructor = getMetricConstructor(opts.type)

    createdMetrics[metric] = new MetricConstructor({
      ...(opts as object),
      name: `${prefix}${opts.name}`,
      help: opts.help,
      registers: [...(opts.registers ?? []), registry],
      labelNames: [...(opts.labelNames ?? []), ...Object.keys(opts.customLabels ?? {})],
      ...(opts.type === 'histogram' &&
        opts.buckets && {
          buckets: opts.buckets,
        }),
    })
  }

  return createdMetrics as CreatedMetrics
}

canonicalizeFilePath = (
  filePath: string,
  outputDir: string,
  baseUrl: string,
  canonicalize: boolean = true
): { routePath: string; url: string } => {
  const posixFilePath = filePath.replace(/\\/g, '/')
  const posixOutputDir = outputDir.replace(/\\/g, '/')
  const outputDirCanonical = path.posix.resolve(path.posix.normalize(posixOutputDir))
  const filePathResolved = path.posix.resolve(path.posix.normalize(posixFilePath))
  const relativePath = path.relative(outputDirCanonical, filePathResolved)

  let routePath = '/' + relativePath
  if (routePath.endsWith('/index.html')) {
    routePath = routePath.slice(0, -'index.html'.length) || '/'
  } else if (routePath.endsWith('.html')) {
    routePath = routePath.slice(0, -'.html'.length)
  }
  const canonicalBaseUrl = baseUrl.endsWith('/') ? baseUrl : `${baseUrl}/`
  let url: string
  if (relativePath.endsWith('index.html')) {
    const dir = relativePath.slice(0, -'index.html'.length)
    url = new URL(dir, canonicalBaseUrl).toString()
  } else if (canonicalize && relativePath.endsWith('.html')) {
    url = new URL(relativePath.slice(0, -'.html'.length), canonicalBaseUrl).toString()
  } else {
    url = new URL(relativePath, canonicalBaseUrl).toString()
  }
  return { routePath, url }
}

function respondWithOpenApiDocument(
  c: Context,
  input?: string | Record<string, any>,
  format: 'json' | 'yaml' = 'json',
) {
  if (!input) {
    return c.text('Not found', 404)
  }

  try {
    const document = normalize(input)

    // JSON
    if (format === 'json') {
      return c.json(document)
    }

    // YAML
    try {
      const yamlDocument = toYaml(normalize(document))

      c.header('Content-Type', 'text/yaml')
      return c.text(yamlDocument, 200, {
        'Content-Type': 'application/yaml; charset=UTF-8',
      })
    } catch (error) {
      return c.json(
        {
          error: 'Failed to convert document to YAML',
          message: error instanceof Error ? error.message : 'Unknown error occurred',
        },
        500,
      )
    }
  } catch (error) {
    return c.json(
      {
        error: 'Failed to parse OpenAPI document',
        message: error instanceof Error ? error.message : 'Unknown error occurred',
      },
      400,
    )
  }
}

function getExampleFromResponse(
  c: Context,
  statusCode: string,
  responses: OpenAPIV3_1.ResponsesObject | undefined,
): any {
  if (!responses) {
    return null
  }

  const response = getResolvedRef(responses[statusCode] || responses.default)

  if (!response) {
    return null
  }

  const supportedContentTypes = Object.keys(response.content ?? {})

  // If no content types are defined, return null
  if (supportedContentTypes.length === 0) {
    return null
  }

  // Content-Type negotiation - prefer application/json
  const acceptedContentType = accepts(c, {
    header: 'Accept',
    supports: supportedContentTypes,
    default: supportedContentTypes.includes('application/json')
      ? 'application/json'
      : (supportedContentTypes[0] ?? 'text/plain;charset=UTF-8'),
  })

  const acceptedResponse = response.content?.[acceptedContentType]

  if (!acceptedResponse) {
    return null
  }

  // Extract example from example property or generate from schema
  return acceptedResponse.example !== undefined
    ? acceptedResponse.example
    : acceptedResponse.schema
      ? getExampleFromSchema(getResolvedRefDeep(acceptedResponse.schema), {
          emptyString: 'string',
          variables: c.req.param(),
          mode: 'read',
        })
      : null
}

async function deleteComment(userId: string, id: string) {
  const [existing] = await db
    .select({
      id: activityTable.id,
      content: activityTable.content,
      taskId: activityTable.taskId,
    })
    .from(activityTable)
    .where(and(eq(activityTable.id, id), eq(activityTable.userId, userId)))
    .limit(1);

  if (!existing) {
    throw new HTTPException(404, {
      message: "Comment not found or you are not the author",
    });
  }

  const [deletedComment] = await db
    .delete(activityTable)
    .where(and(eq(activityTable.id, id), eq(activityTable.userId, userId)))
    .returning();

  if (!deletedComment) {
    throw new HTTPException(404, {
      message: "Comment not found or you are not the author",
    });
  }

  const [task] = await db
    .select({ projectId: taskTable.projectId })
    .from(taskTable)
    .where(eq(taskTable.id, deletedComment.taskId))
    .limit(1);

  if (task) {
    await publishEvent("comment.deleted", {
      ...deletedComment,
      projectId: task.projectId,
      userId,
    });
  }

  deleteOrphanedAssets(existing.content, null, {
    taskId: existing.taskId,
  }).catch(() => {});

  return deletedComment;
}

async function updateComment(userId: string, id: string, content: string) {
  const [existing] = await db
    .select({
      id: activityTable.id,
      content: activityTable.content,
      taskId: activityTable.taskId,
    })
    .from(activityTable)
    .where(and(eq(activityTable.id, id), eq(activityTable.userId, userId)))
    .limit(1);

  if (!existing) {
    throw new HTTPException(404, {
      message: "Comment not found or you are not the author",
    });
  }

  const [updated] = await db
    .update(activityTable)
    .set({ content })
    .where(and(eq(activityTable.id, id), eq(activityTable.userId, userId)))
    .returning();

  if (!updated) {
    throw new HTTPException(404, {
      message: "Comment not found or you are not the author",
    });
  }

  const [task] = await db
    .select({ projectId: taskTable.projectId })
    .from(taskTable)
    .where(eq(taskTable.id, updated.taskId))
    .limit(1);

  if (task) {
    await publishEvent("comment.updated", {
      ...updated,
      projectId: task.projectId,
      userId,
    });
  }

  deleteOrphanedAssets(existing.content, content, {
    taskId: existing.taskId,
  }).catch(() => {});

  return updated;
}

async function getGiteaIntegration(projectId: string) {
  const integration = await db.query.integrationTable.findFirst({
    where: and(
      eq(integrationTable.projectId, projectId),
      eq(integrationTable.type, "gitea"),
    ),
  });

  if (!integration) {
    return null;
  }

  const config = JSON.parse(integration.config) as GiteaConfig;

  const apiBase = normalizeApiServerUrl(
    process.env.KANEO_API_URL || "http://localhost:1337",
  );

  return {
    id: integration.id,
    projectId: integration.projectId,
    baseUrl: config.baseUrl,
    repositoryOwner: config.repositoryOwner,
    repositoryName: config.repositoryName,
    maskedAccessToken: maskToken(config.accessToken),
    webhookUrl: `${apiBase.replace(/\/$/, "")}/gitea-integration/webhook/${integration.id}`,
    webhookSecret: config.webhookSecret ?? "",
    branchPattern: config.branchPattern || defaultGiteaConfig.branchPattern,
    commentTaskLinkOnGiteaIssue: config.commentTaskLinkOnGiteaIssue !== false,
    isActive: integration.isActive,
    createdAt: integration.createdAt,
    updatedAt: integration.updatedAt,
  };
}

async function listGiteaRepositories({
  baseUrl,
  accessToken,
}: {
  baseUrl: string;
  accessToken: string;
}): Promise<{ repositories: RepoRow[] }> {
  const normalized = normalizeGiteaBaseUrl(baseUrl);

  try {
    await verifyGiteaToken(normalized, accessToken);
  } catch {
    throw new HTTPException(401, {
      message: "Invalid Gitea token or could not reach instance.",
    });
  }

  const client = createGiteaClient({
    baseUrl: normalized,
    accessToken,
  });

  const all: RepoRow[] = [];
  let page = 1;

  while (true) {
    const batch = await client.listUserRepos(page, 50);
    if (!batch.length) break;

    for (const repo of batch) {
      const ownerLogin = repo.owner?.login ?? repo.owner?.username ?? "";
      all.push({
        id: repo.id,
        name: repo.name,
        full_name: repo.full_name,
        private: repo.private,
        owner: { login: ownerLogin },
        html_url: repo.html_url,
      });
    }

    if (batch.length < 50) break;
    page += 1;
    if (page > 50) break;
  }

  return { repositories: all };
}

async function runStartupTasks() {
  const currentDir = dirname(fileURLToPath(import.meta.url));

  await prepareDatabaseStartup({
    waitForDatabase: async () => {
      await waitForDatabase({
        query: async () => {
          await getDatabase().execute(sql`SELECT 1`);
        },
      });
    },
    runStartupMigrations: async () => {
      await migrateWorkspaceUserEmail();
      await migrateSessionColumn();

      console.log("🔄 Migrating database...");
      await migrate(getDatabase(), {
        migrationsFolder: `${currentDir}/../drizzle`,
      });
      console.log("✅ Database migrated successfully!");
    },
  });

  // After Drizzle migrations: apikey table must exist so we can align columns
  // with Better Auth (reference_id + nullable user_id).
  await migrateApiKeyReferenceId();

  await migrateNotificationPreferencesSchema();
  await migrateGitHubIntegration();
  await migrateColumns();
  await seedDefaultWorkspaceRoles();

  initializePlugins();
  initializeScheduler();
  await initializeWebSocketAdapter();
}

async function startServer(
  injectWebSocket: ReturnType<typeof createNodeWebSocket>["injectWebSocket"],
  port = 1337,
) {
  try {
    await runStartupTasks();
  } catch (error) {
    console.error("❌ Database migration failed!", error);
    process.exit(1);
  }

  let shuttingDown = false;

  const server = serve(
    {
      fetch: app.fetch,
      port,
    },
    () => {
      console.log(
        `⚡ API is running at ${process.env.KANEO_API_URL || "http://localhost:1337"}`,
      );
    },
  );

  injectWebSocket(server);

  const gracefulShutdown = async () => {
    if (shuttingDown) return;
    shuttingDown = true;

    console.log("🛑 Shutting down gracefully...");
    shutdownScheduler();
    await shutdownWebSocketAdapter();
    server.close();
    process.exit(0);
  };

  process.on("SIGTERM", () => {
    void gracefulShutdown();
  });

  process.on("SIGINT", () => {
    void gracefulShutdown();
  });
}

function decryptSecret(
  value: string | null | undefined,
): string | null | undefined {
  if (value === undefined || value === null || !isEncryptedSecret(value)) {
    return value;
  }

  const payload = value.slice(SECRET_PREFIX.length);
  const [iv, authTag, encrypted] = payload.split(".");

  if (!iv || !authTag || !encrypted) {
    throw new HTTPException(500, {
      message: "Invalid encrypted notification secret payload",
    });
  }

  try {
    const decipher = createDecipheriv(
      SECRET_ALGORITHM,
      requireSecretEncryptionKey(),
      decodePart(iv),
    );
    decipher.setAuthTag(decodePart(authTag));

    return Buffer.concat([
      decipher.update(decodePart(encrypted)),
      decipher.final(),
    ]).toString("utf8");
  } catch (error) {
    if (error instanceof HTTPException) {
      throw error;
    }
    throw new HTTPException(500, {
      message: "Failed to decrypt notification secret",
    });
  }
}

async function createNotification({
  userId,
  title,
  content,
  type,
  eventData,
  resourceId,
  resourceType,
}: {
  userId: string;
  title?: string | null;
  content?: string | null;
  type?: string;
  eventData?: Record<string, unknown> | null;
  resourceId?: string;
  resourceType?: string;
}) {
  const [notification] = await db
    .insert(notificationTable)
    .values({
      id: createId(),
      userId,
      title: title ?? null,
      content: content ?? null,
      type: type || "info",
      eventData: eventData ?? null,
      resourceId: resourceId || null,
      resourceType: resourceType || null,
    })
    .returning();

  if (notification) {
    await publishEvent("notification.created", {
      notificationId: notification.id,
      userId,
    });
    void deliverNotification(notification.id).catch((error) => {
      console.error("Failed to deliver notification", {
        notificationId: notification.id,
        error,
      });
    });
  }

  return notification;
}

async function getProjects(workspaceId: string, includeArchived = false) {
  const projects = await db.query.projectTable.findMany({
    where: includeArchived
      ? eq(projectTable.workspaceId, workspaceId)
      : and(
          eq(projectTable.workspaceId, workspaceId),
          isNull(projectTable.archivedAt),
        ),
    with: {
      tasks: true,
    },
  });

  const projectsWithStatistics = projects.map((project) => {
    const totalTasks = project.tasks.length;
    const completedTasks = project.tasks.filter(
      (task) => task.status === "done" || task.status === "archived",
    ).length;
    const completionPercentage =
      totalTasks > 0 ? Math.round((completedTasks / totalTasks) * 100) : 0;

    const dueDate = project.tasks.reduce((earliest: Date | null, task) => {
      if (!earliest || (task.dueDate && task.dueDate < earliest))
        return task.dueDate;
      return earliest;
    }, null);

    return {
      ...project,
      statistics: {
        completionPercentage,
        totalTasks,
        dueDate,
      },
      archivedTasks: [],
      plannedTasks: [],
      columns: [],
    };
  });

  return projectsWithStatistics;
}

function resolveRedisMode(): RedisMode {
  const clusterNodes = process.env.REDIS_CLUSTER_NODES;
  if (clusterNodes) {
    return {
      mode: "cluster",
      nodes: parseNodeList(clusterNodes, "REDIS_CLUSTER_NODES", 6379),
      password: process.env.REDIS_PASSWORD,
    };
  }

  const sentinels = process.env.REDIS_SENTINELS;
  if (sentinels) {
    return {
      mode: "sentinel",
      sentinels: parseNodeList(sentinels, "REDIS_SENTINELS", 26379),
      name: process.env.REDIS_SENTINEL_MASTER_NAME || "mymaster",
      password: process.env.REDIS_PASSWORD,
      sentinelPassword: process.env.REDIS_SENTINEL_PASSWORD,
      enableTLSForSentinelMode: process.env.REDIS_SENTINEL_TLS === "true",
    };
  }

  const url = process.env.REDIS_URL;
  if (!url) {
    throw new Error(
      "REDIS_URL, REDIS_SENTINELS, or REDIS_CLUSTER_NODES must be set",
    );
  }
  return { mode: "standalone", url };
}

async function deleteTaskRelation(id: string, userId: string) {
  const [rel] = await db
    .select({
      sourceTaskId: taskRelationTable.sourceTaskId,
      targetTaskId: taskRelationTable.targetTaskId,
    })
    .from(taskRelationTable)
    .where(eq(taskRelationTable.id, id))
    .limit(1);

  if (!rel) {
    throw new HTTPException(404, {
      message: "Task relation not found",
    });
  }

  const [task] = await db
    .select({ projectId: taskTable.projectId })
    .from(taskTable)
    .where(eq(taskTable.id, rel.sourceTaskId))
    .limit(1);

  const [relation] = await db
    .delete(taskRelationTable)
    .where(eq(taskRelationTable.id, id))
    .returning();

  if (!relation) {
    throw new HTTPException(404, {
      message: "Task relation not found",
    });
  }

  if (task) {
    await publishEvent("task-relation.deleted", {
      ...relation,
      taskId: rel.sourceTaskId,
      sourceTaskId: rel.sourceTaskId,
      targetTaskId: rel.targetTaskId,
      projectId: task.projectId,
      userId,
    });
  }

  return relation;
}

async function resolveDestinationStatus(
  destinationProjectId: string,
  currentStatus: string,
  requestedStatus?: string,
) {
  const destinationColumns = await db
    .select({
      id: columnTable.id,
      slug: columnTable.slug,
      position: columnTable.position,
    })
    .from(columnTable)
    .where(eq(columnTable.projectId, destinationProjectId))
    .orderBy(asc(columnTable.position));

  if (destinationColumns.length === 0) {
    throw new HTTPException(400, {
      message: "Destination project does not have a workflow",
    });
  }

  const requestedColumn = requestedStatus
    ? destinationColumns.find((column) => column.slug === requestedStatus)
    : null;

  if (requestedStatus && !requestedColumn) {
    throw new HTTPException(400, {
      message: "Selected status is not valid for the destination project",
    });
  }

  const matchingCurrentColumn = destinationColumns.find(
    (column) => column.slug === currentStatus,
  );

  return requestedColumn ?? matchingCurrentColumn ?? destinationColumns[0];
}

async function updateTaskDescription({
  id,
  description,
  currentUserId,
}: {
  id: string;
  description: string;
  currentUserId: string;
}) {
  const existingTask = await db.query.taskTable.findFirst({
    where: eq(taskTable.id, id),
  });

  if (!existingTask) {
    throw new HTTPException(404, {
      message: "Task not found",
    });
  }

  const [updatedTask] = await db
    .update(taskTable)
    .set({ description })
    .where(eq(taskTable.id, id))
    .returning();

  if (!updatedTask) {
    throw new HTTPException(500, {
      message: "Failed to update task description",
    });
  }

  await publishEvent("task.description_changed", {
    taskId: updatedTask.id,
    projectId: updatedTask.projectId,
    userId: currentUserId,
    oldDescription: existingTask.description,
    newDescription: description,
    type: "description_changed",
  });

  deleteOrphanedAssets(existingTask.description, description, {
    taskId: id,
  }).catch(() => {});

  return updatedTask;
}

async function updateTaskDueDate({
  id,
  dueDate,
  currentUserId,
}: {
  id: string;
  dueDate: Date | null;
  currentUserId: string;
}) {
  const existingTask = await db.query.taskTable.findFirst({
    where: eq(taskTable.id, id),
  });

  if (!existingTask) {
    throw new HTTPException(404, {
      message: "Task not found",
    });
  }

  // Clear sent reminders so new due date triggers fresh notifications
  await db
    .delete(taskReminderSentTable)
    .where(eq(taskReminderSentTable.taskId, id));

  const [updatedTask] = await db
    .update(taskTable)
    .set({ dueDate: dueDate || null })
    .where(eq(taskTable.id, id))
    .returning();

  if (!updatedTask) {
    throw new HTTPException(500, {
      message: "Failed to update task due date",
    });
  }

  await publishEvent("task.due_date_changed", {
    taskId: updatedTask.id,
    projectId: updatedTask.projectId,
    userId: currentUserId,
    oldDueDate: existingTask.dueDate,
    newDueDate: dueDate,
    title: updatedTask.title,
    type: "due_date_changed",
  });

  return updatedTask;
}

async function updateTimeEntry(params: UpdateTimeEntryParams) {
  const { timeEntryId, startTime, endTime, description } = params;

  const [existingTimeEntry] = await db
    .select()
    .from(timeEntryTable)
    .where(eq(timeEntryTable.id, timeEntryId));

  if (!existingTimeEntry) {
    throw new HTTPException(404, {
      message: "Time entry not found",
    });
  }

  // Calculate duration if both startTime and endTime are provided
  let duration: number | null = null;
  if (endTime) {
    duration = Math.floor((endTime.getTime() - startTime.getTime()) / 1000); // duration in seconds
  }

  const [updatedTimeEntry] = await db
    .update(timeEntryTable)
    .set({
      startTime,
      endTime: endTime || null,
      duration,
      ...(description !== undefined && { description }),
    })
    .where(eq(timeEntryTable.id, timeEntryId))
    .returning();

  return updatedTimeEntry;
}

async function resolveAssetBearerOrCookie(c: Context): Promise<{
  userId: string;
  apiKeyId?: string;
}> {
  const { token, malformed } = parseBearerToken(c.req.header("Authorization"));
  if (malformed) {
    throw new HTTPException(401, { message: "Unauthorized" });
  }

  if (token) {
    const apiKeyResult = await verifyApiKey(token);
    if (apiKeyResult?.valid && apiKeyResult.key) {
      return {
        userId: apiKeyResult.key.userId,
        apiKeyId: apiKeyResult.key.id,
      };
    }
    const sessionResult = await getSessionFromBearerOnlyHeaders(c);
    if (sessionResult?.user?.id) {
      return { userId: sessionResult.user.id };
    }
    throw new HTTPException(401, { message: "Unauthorized" });
  }

  const sessionResult = await auth.api.getSession({
    headers: c.req.raw.headers,
  });
  if (!sessionResult?.user) {
    throw new HTTPException(401, { message: "Unauthorized" });
  }

  return { userId: sessionResult.user.id };
}
